  "plan": "Write a Python script that generates all the intermediate values passed to the C program, then use a C program to verify step by step.",
  "commands": [
    {
      "keystrokes": "cat > /app/verify_c.c << 'ENDSCRIPT'
#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>

typedef uint32_t u32;

typedef struct {
    u32 gl_a, gl_b;
    u32 R3_a, R3_b;
    u32 T;
} PairData;

u32 g_function(u32 a, u32 b, u32 x) {
    u32 temp = (a + b + x) & 0xFF;
    return ((temp << 2) | (temp >> 6)) & 0xFF;
}

u32 f_function(u32 input_val) {
    u32 x[4], y[4];
    for (int i = 0; i < 4; i++) {
        x[i] = input_val & 0xFF;
        input_val >>= 8;
    }
    y[2] = g_function(x[3] ^ x[2], x[1] ^ x[0], 1);
    y[3] = g_function(x[3], y[2], 0);
    y[1] = g_function(x[1] ^ x[0], y[2], 0);
    y[0] = g_function(x[0], y[1], 1);
    u32 output = 0;
    for (int i = 0; i < 4; i++) {
        output |= y[i] << (8 * i);
    }
    return output & 0xFFFFFFFF;
}

int main() {
    // Known keys from the test
    u32 keys[6];
    keys[0] = 0x31c40f00;
    keys[1] = 0xf136f4a2;
    keys[2] = 0x5ca021b0;
    keys[3] = 0x39f60aae;
    keys[4] = 0x68d473f8;
    keys[5] = 0x41d02297;

    // Ciphertexts from the test
    u32 C_a_hi = 0x5ee2b104;
    u32 C_a_lo = 0x93b7534c;
    u32 C_b_hi = 0x12868091;
    u32 C_b_lo = 0x82cdaeff;

    u64 C_a = ((u64)C_a_hi << 32) | C_a_lo;
    u64 C_b = ((u64)C_b_hi << 32) | C_b_lo;

    u32 gl_a = C_a_hi;
    u32 gl_b = C_b_hi;
    u32 R3_a = C_a_lo ^ C_a_hi;
    u32 R3_b = C_b_lo ^ C_b_hi;

    printf("Known keys:\n");
    printf("  key[4] = 0x%08x\n", keys[4]);
    printf("  key[5] = 0x%08x\n", keys[5]);
    printf("\n");

    printf("Ciphertext inputs:\n");
    printf("  gl_a = 0x%08x\n", gl_a);
    printf("  gl_b = 0x%08x\n", gl_b);
    printf("  R3_a = 0x%08x\n", R3_a);
    printf("  R3_b = 0x%08x\n", R3_b);
    printf("\n");

    // Compute L3 values
    u32 L3_a = gl_a ^ f_function(R3_a ^ keys[5]);
    u32 L3_b = gl_b ^ f_function(R3_b ^ keys[5]);

    printf("Computed L3 values:\n");
    printf("  L3_a = 0x%08x\n", L3_a);
    printf("  L3_b = 0x%08x\n", L3_b);
    printf("\n");

    // Compute T
    u32 delta = 0x12345678;
    u32 T = R3_a ^ R3_b ^ delta;
    printf("T = R3_a ^ R3_b ^ delta = 0x%08x\n", T);

    // Check f(L3_a ^ k4) ^ f(L3_b ^ k4)
    u32 lhs = f_function(L3_a ^ keys[4]) ^ f_function(L3_b ^ keys[4]);
    printf("f(L3_a ^ k4) ^ f(L3_b ^ k4) = 0x%08x\n", lhs);
    printf("Match: %s\n", lhs == T ? "true" : "false");

    return 0;
}
